// স্প্রেড অপারেটর
const arr1 = [1, 2, 3];
const arr2 = [...arr1, 4, 5];
console.log(arr2); // [1, 2, 3, 4, 5]

const obj1 = { a: 1, b: 2 };
const obj2 = { ...obj1, c: 3 };
console.log(obj2); // { a: 1, b: 2, c: 3 }

const [first, second, ...rest] = [10, 20, 30, 40];
console.log(first, second, rest); // 10 20 [30, 40]

const { name, age = 18 } = { name: "তানিম" };
console.log(name, age); // তানিম 18

const user = { profile: { city: "খুলনা" } };
console.log(user.profile?.city);       // খুলনা
console.log(user.address?.zip);        // undefined, error হয় না

let input = null;
let value = input ?? "ডিফল্ট মান";
console.log(value); // ডিফল্ট মান
